module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

    reg [3:0] cnt;
    reg start_cnt;
    reg res_valid_reg;
    reg res_ready_reg;
    reg [8:0] neg_divisor;
    reg [8:0] remainder;
    reg [8:0] quotient;
    reg [16:0] SR;

    always@(posedge clk or posedge rst) begin
        if(rst) begin
            cnt <= 4'd0;
            start_cnt <= 1'b0;
            res_valid_reg <= 1'b0;
            res_ready_reg <= 1'b0;
            neg_divisor <= 9'd0;
            remainder <= 9'd0;
            quotient <= 9'd0;
            SR <= 17'd0;
        end
        else begin
            case({res_valid_reg,res_ready_reg})
                2'b00: begin
                    if(opn_valid && !res_valid_reg) begin
                        cnt <= 4'd1;
                        start_cnt <= 1'b1;
                        res_valid_reg <= 1'b0;
                        res_ready_reg <= 1'b0;
                        neg_divisor <= {~|divisor[7],~divisor} + 1;
                        remainder <= {1'b0,dividend};
                        quotient <= 9'd0;
                        SR <= {1'b0,dividend,1'b0};
                    end
                end
                2'b01: begin
                    if(cnt==4'd8) begin
                        cnt <= 4'd0;
                        start_cnt <= 1'b0;
                        res_valid_reg <= 1'b1;
                        res_ready_reg <= 1'b0;
                        SR <= {remainder,quotient[7]};
                    end
                    else begin
                        cnt <= cnt + 1;
                        start_cnt <= 1'b1;
                        res_valid_reg <= 1'b0;
                        res_ready_reg <= 1'b0;
                        neg_divisor <= {~|divisor[7],~divisor} + 1;
                        remainder <= {1'b0,SR[16:9]} - neg_divisor;
                        quotient <= {quotient[6:0],~remainder[8]};
                        SR <= {remainder[7:0],SR[8:1]};
                    end
                end
                default: begin
                    cnt <= 4'd0;
                    start_cnt <= 1'b0;
                    res_valid_reg <= 1'b0;
                    res_ready_reg <= 1'b0;
                    neg_divisor <= 9'd0;
                    remainder <= 9'd0;
                    quotient <= 9'd0;
                    SR <= 17'd0;
                end
            endcase
        end
    end

    assign res_valid = res_valid_reg;
    assign result = {remainder[7:0],quotient[7:0]};
endmodule
